// ─── COMPONENTS ──────────────────────────────────────────────────────────────

function Tag({ label }) {
  const s = TAG_STYLE[label] || { bg:"#F3F4F6", color:"#374151", border:"#D1D5DB" };
  return (
    <span style={{
      background: s.bg, color: s.color, border: `1px solid ${s.border}`,
      borderRadius: 20, padding: "2px 9px", fontSize: 10, fontWeight: 700,
      letterSpacing: 0.3, whiteSpace: "nowrap"
    }}>{label}</span>
  );
}

function StockBadge({ status }) {
  return (
    <span style={{
      display:"inline-flex", alignItems:"center", gap: 4, fontSize: 11, fontWeight: 600,
      color: status === "available" ? COLORS.green : "#D97706",
    }}>
      <span style={{
        width:7, height:7, borderRadius:"50%",
        background: status === "available" ? COLORS.green : "#F59E0B",
        boxShadow: `0 0 0 2px ${status === "available" ? "#BBF7D0" : "#FDE68A"}`
      }}/>
      {status === "available" ? "In Stock" : "Limited"}
    </span>
  );
}

function QuantitySelector({ value, onChange }) {
  return (
    <div style={{ display:"flex", alignItems:"center", gap:0, borderRadius:10, overflow:"hidden", border:`1.5px solid ${COLORS.gray200}`, background:COLORS.white }}>
      <button onClick={() => onChange(Math.max(0, value-1))} style={{
        width:34, height:34, border:"none", background: value>0 ? COLORS.blue : COLORS.gray100,
        color: value>0 ? COLORS.white : COLORS.gray400, fontSize:18, fontWeight:700,
        cursor: value>0 ? "pointer":"default", transition:"all 0.15s"
      }}>−</button>
      <span style={{ width:38, textAlign:"center", fontWeight:700, fontSize:15, color:COLORS.navy }}>{value}</span>
      <button onClick={() => onChange(value+1)} style={{
        width:34, height:34, border:"none", background: COLORS.blue, color:COLORS.white,
        fontSize:18, fontWeight:700, cursor:"pointer", transition:"all 0.15s"
      }}>+</button>
    </div>
  );
}

function MedicineCard({ med, qty, onQtyChange }) {
  const [hovered, setHovered] = useState(false);
  return (
    <div onMouseEnter={()=>setHovered(true)} onMouseLeave={()=>setHovered(false)} style={{
      background:COLORS.white, borderRadius:16, border:`1.5px solid ${hovered ? COLORS.blue : COLORS.gray200}`,
      padding:"18px 16px 14px", display:"flex", flexDirection:"column", gap:10,
      boxShadow: hovered ? `0 8px 32px ${COLORS.shadow}` : `0 2px 8px rgba(0,0,0,0.04)`,
      transition:"all 0.2s cubic-bezier(.4,0,.2,1)", cursor:"default"
    }}>
      <div style={{ display:"flex", alignItems:"flex-start", justifyContent:"space-between" }}>
        <div style={{
          width:46, height:46, borderRadius:12, background: qty>0 ? "#EFF6FF" : COLORS.gray50,
          display:"flex", alignItems:"center", justifyContent:"center", fontSize:22,
          border:`1.5px solid ${qty>0 ? COLORS.blue+"33" : COLORS.gray200}`,
          transition:"all 0.2s"
        }}>{med.image}</div>
        <StockBadge status={med.stock} />
      </div>
      <div>
        <div style={{ fontWeight:800, fontSize:14, color:COLORS.navy, lineHeight:1.3 }}>{med.name}</div>
        <div style={{ fontSize:12, color:COLORS.gray400, fontWeight:500, marginTop:2 }}>{med.brand}</div>
        <div style={{ fontSize:11, color:COLORS.blue, fontWeight:600, marginTop:3 }}>{med.category}</div>
      </div>
      {med.tags.length > 0 && (
        <div style={{ display:"flex", flexWrap:"wrap", gap:4 }}>
          {med.tags.map(t=><Tag key={t} label={t} />)}
        </div>
      )}
      <div style={{ display:"flex", alignItems:"center", justifyContent:"space-between", marginTop:2 }}>
        <QuantitySelector value={qty} onChange={onQtyChange} />
        {qty > 0 && (
          <span style={{ fontSize:12, color:COLORS.green, fontWeight:700, animation:"fadeIn 0.2s" }}>✓ Added</span>
        )}
      </div>
    </div>
  );
}

